import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { FaCar, FaUsers, FaCog } from 'react-icons/fa';
import './CarSearch.css';

const CarSearch = () => {
  const [cars, setCars] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    category: '',
    transmission: '',
    minPrice: '',
    maxPrice: ''
  });

  useEffect(() => {
    fetchCars();
  }, [filters]);

  const fetchCars = async () => {
    try {
      const params = new URLSearchParams();
      Object.keys(filters).forEach(key => {
        if (filters[key]) params.append(key, filters[key]);
      });
      
      const res = await axios.get(`http://localhost:5000/api/cars?${params}`);
      setCars(res.data.data);
    } catch (error) {
      console.error('Error fetching cars:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (e) => {
    setFilters({ ...filters, [e.target.name]: e.target.value });
  };

  const resetFilters = () => {
    setFilters({ category: '', transmission: '', minPrice: '', maxPrice: '' });
  };

  if (loading) return <div className="loading">Loading cars...</div>;

  return (
    <div className="car-search">
      <div className="container">
        <h1>Browse Our Fleet</h1>
        
        <div className="search-layout">
          <aside className="filters-sidebar">
            <h3>Filters</h3>
            <div className="filter-group">
              <label>Category</label>
              <select name="category" value={filters.category} onChange={handleFilterChange}>
                <option value="">All Categories</option>
                <option value="economy">Economy</option>
                <option value="suv">SUV</option>
                <option value="luxury">Luxury</option>
                <option value="van">Van</option>
              </select>
            </div>
            <div className="filter-group">
              <label>Transmission</label>
              <select name="transmission" value={filters.transmission} onChange={handleFilterChange}>
                <option value="">All Types</option>
                <option value="automatic">Automatic</option>
                <option value="manual">Manual</option>
              </select>
            </div>
            <div className="filter-group">
              <label>Min Price ($/day)</label>
              <input
                type="number"
                name="minPrice"
                value={filters.minPrice}
                onChange={handleFilterChange}
                placeholder="0"
              />
            </div>
            <div className="filter-group">
              <label>Max Price ($/day)</label>
              <input
                type="number"
                name="maxPrice"
                value={filters.maxPrice}
                onChange={handleFilterChange}
                placeholder="1000"
              />
            </div>
            <button onClick={resetFilters} className="btn btn-secondary">Reset Filters</button>
          </aside>

          <div className="cars-grid">
            {cars.length === 0 ? (
              <p className="no-results">No cars found matching your criteria</p>
            ) : (
              cars.map(car => (
                <div key={car._id} className="car-card">
                  <div className="car-image">
                    <img src={car.images[0] || '/placeholder-car.jpg'} alt={`${car.make} ${car.model}`} />
                    <span className="car-category">{car.category}</span>
                  </div>
                  <div className="car-info">
                    <h3>{car.make} {car.model}</h3>
                    <p className="car-year">{car.year}</p>
                    <div className="car-features">
                      <span><FaUsers /> {car.seatingCapacity} Seats</span>
                      <span><FaCog /> {car.transmission}</span>
                      <span><FaCar /> {car.fuelType}</span>
                    </div>
                    <div className="car-footer">
                      <div className="car-price">
                        <span className="price">${car.pricePerDay}</span>
                        <span className="period">/day</span>
                      </div>
                      <Link to={`/cars/${car._id}`}>
                        <button className="btn btn-primary">View Details</button>
                      </Link>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default CarSearch;
